mapper.select:
SELECT id, name, username, real_name, partner_id, status, deleted FROM sys_user
AND ( name ILIKE CONCAT('%', #{query.keyword}, '%') OR username ILIKE CONCAT('%', #{query.keyword}, '%') OR real_name ILIKE CONCAT('%', #{query.keyword}, '%') )
AND username ILIKE CONCAT('%', #{query.username}, '%')
AND status = #{query.status}
AND deleted = #{query.deleted}
ORDER BY id DESC
